        return f"{m.group(3)}-{m.group(2)}-{m.group(1)} 00:00:00"
    # YYYY-MM-DD bare date
    m = re.match(r"(\d{4}-\d{2}-\d{2})$", raw)
    if m:
        return f"{m.group(1)} 00:00:00"
    raise ValueError(f"Unrecognised timestamp format: {raw!r}")

